import openpyxl, copy, io, base64, json
from openpyxl import load_workbook, Workbook
from openpyxl.styles import Alignment
from openpyxl.utils import get_column_letter, column_index_from_string
from datetime import datetime
from http.server import BaseHTTPRequestHandler

RESOL_B64 = ""
LIST_B64  = ""
SETTLE_B64 = ""

def set_val(ws, row, col, value, align=None):
    """병합셀 포함 안전하게 값 쓰기"""
    cell = ws.cell(row=row, column=col)
    if cell.__class__.__name__ == "MergedCell":
        for rng in ws.merged_cells.ranges:
            if rng.min_row<=row<=rng.max_row and rng.min_col<=col<=rng.max_col:
                top = ws.cell(rng.min_row, rng.min_col)
                if top.__class__.__name__ != "MergedCell":
                    top.value = value
                    if align: top.alignment = align
                break
    else:
        cell.value = value
        if align: cell.alignment = align

def apply_merge_list(ws, merge_strings, row_offset=0):
    """병합셀 문자열 목록을 offset 적용해서 추가"""
    for mc in merge_strings:
        # A3:E3 → offset 적용 → A(3+o):E(3+o)
        parts = mc.split(':')
        def shift(addr):
            col_str = ''.join(c for c in addr if c.isalpha())
            row_num = int(''.join(c for c in addr if c.isdigit()))
            return f"{col_str}{row_num + row_offset}"
        new_mc = f"{shift(parts[0])}:{shift(parts[1])}"
        try: ws.merge_cells(new_mc)
        except: pass

def fill_page(ws, o, page, page_total, biz_title, yy, mm, dd, page_num=0):
    center = Alignment(horizontal="center", vertical="center", wrap_text=True)
    set_val(ws,1+o,2,"지   출   결   의   서 ")
    set_val(ws,3+o,1,biz_title)
    set_val(ws,3+o,11,"결\n\n재",center)
    set_val(ws,3+o,12,"담당"); set_val(ws,3+o,14,"사무총장"); set_val(ws,3+o,16,"재무이사")
    set_val(ws,6+o,1,"작성일자"); set_val(ws,6+o,3,yy); set_val(ws,6+o,5,"년")
    set_val(ws,6+o,6,mm); set_val(ws,6+o,7,"월"); set_val(ws,6+o,8,dd); set_val(ws,6+o,10,"일")
    set_val(ws,6+o,11,"처리사항"); set_val(ws,6+o,14,"구분"); set_val(ws,6+o,16,"결제방식")
    set_val(ws,7+o,1,"결재일자"); set_val(ws,7+o,3,yy); set_val(ws,7+o,5,"년")
    set_val(ws,7+o,6,mm); set_val(ws,7+o,7,"월"); set_val(ws,7+o,8,"__"); set_val(ws,7+o,10,"일")
    set_val(ws,7+o,14,"영수증"); set_val(ws,7+o,16,"계좌이체")
    set_val(ws,8+o,1,page_total); set_val(ws,8+o,11,page_total)
    set_val(ws,10+o,1,"순번"); set_val(ws,10+o,2,"계 정 과 목")
    set_val(ws,10+o,5,"적         요"); set_val(ws,10+o,13,"금       액"); set_val(ws,10+o,16,"비 고")
    for i in range(20):
        r=11+i+o; set_val(ws,r,1,page_num*20+i+1)  # 순번: 1페이지 1~20, 2페이지 21~40...
        if i<len(page):
            c=page[i]
            amt=(c.get("fee",0) or 0)+(c.get("stamp",0) or 0)+(c.get("delivery",0) or 0)
            num=(c.get("num","") or "").replace("국부 ","").replace("서금 ","")
            if num.startswith("미인식"): num=""
            lawyer=c.get("lawyer","") or ""
            # 계정과목: 기본은 법률구조사업비, accountType이 일반관리비면 변경
            acct_type = c.get("accountType","법률구조사업비")
            if acct_type == "일반관리비":
                acct_label = "일반관리비\n전세피해자사업비"
            else:
                acct_label = "법률구조사업비\n전세피해자사업비"
            if not lawyer and not num:
                desc=(c.get("client","") or "")+" "+(c.get("case","") or c.get("caseName","") or "")
            else:
                desc=lawyer+" 弁 "+num+"호 "+(c.get("client","") or "")+" "+(c.get("case","") or c.get("caseName","") or "")
            set_val(ws,r,2,acct_label,center)
            set_val(ws,r,5,desc); set_val(ws,r,13,amt)
            set_val(ws,r,16,c.get("note","") or c.get("type",""))
        else:
            for col in [2,5,13,16]: set_val(ws,r,col,None)
    set_val(ws,31+o,1,"계"); set_val(ws,31+o,13,page_total)

def build_excel(cases_data, lawyers_data, biz_short, yy, mm, dd):
    lawyers_dict = {l["name"]:l for l in (lawyers_data or [])}
    wb_src_resol = load_workbook(io.BytesIO(base64.b64decode(RESOL_B64)))
    wb_src_list  = load_workbook(io.BytesIO(base64.b64decode(LIST_B64)))

    src_name  = "26년사업비-국토부 (5월)" if biz_short=="국토부" else "26년사업비-서민 (5월)"
    biz_label = "국토부" if biz_short=="국토부" else "서민"
    biz_full  = "국토부" if biz_short=="국토부" else "서민금융재단"
    biz_title = f"{yy}년 소송구조({biz_full}) / 전세피해자"
    new_name  = f"26년사업비-{biz_label} ({mm}월)"

    ws_src = wb_src_resol[src_name]

    # 병합셀 목록을 문자열로 미리 추출 (openpyxl 내부 처리 후)
    merge_strings = [str(m) for m in ws_src.merged_cells.ranges]

    wb_new = Workbook(); wb_new.remove(wb_new.active)
    ws_new = wb_new.create_sheet(new_name)

    # 열너비
    for col,dim in ws_src.column_dimensions.items():
        ws_new.column_dimensions[col].width=dim.width

    pages = [cases_data[i:i+20] for i in range(0,max(len(cases_data),1),20)]

    for p_idx,page in enumerate(pages):
        o = p_idx*32
        page_total=sum((c.get("fee",0) or 0)+(c.get("stamp",0) or 0)+(c.get("delivery",0) or 0) for c in page)

        # 행높이
        for rn,dim in ws_src.row_dimensions.items():
            ws_new.row_dimensions[rn+o].height=dim.height

        # 병합셀 (문자열 목록으로)
        apply_merge_list(ws_new, merge_strings, o)

        # 서식 복사
        for row in ws_src.iter_rows(min_row=1,max_row=31):
            for cell in row:
                if cell.__class__.__name__=="MergedCell": continue
                nc=ws_new.cell(row=cell.row+o,column=cell.column)
                if nc.__class__.__name__=="MergedCell": continue
                if cell.has_style:
                    nc.font=copy.copy(cell.font); nc.border=copy.copy(cell.border)
                    nc.fill=copy.copy(cell.fill); nc.number_format=cell.number_format
                    nc.alignment=copy.copy(cell.alignment)

        fill_page(ws_new,o,page,page_total,biz_title,yy,mm,dd,p_idx)

    # ── 인쇄 설정: A4, 페이지당 31행씩 자동 분할 ──
    from openpyxl.worksheet.properties import PageSetupProperties
    ws_new.page_setup.orientation = 'portrait'
    ws_new.page_setup.paperSize   = 9   # A4
    ws_new.page_setup.fitToHeight = 0
    ws_new.page_setup.fitToWidth  = 1
    ws_new.page_setup.scale       = 90
    ws_new.sheet_properties.pageSetUpPr = PageSetupProperties(fitToPage=True)
    ws_new.page_margins.top    = 0.49
    ws_new.page_margins.bottom = 0.1968503937007874
    ws_new.page_margins.left   = 0.7086614173228347
    ws_new.page_margins.right  = 0.7086614173228347
    ws_new.page_margins.header = 0
    ws_new.page_margins.footer = 0

    # print_area: 각 페이지(31행) 전체를 포함
    last_row = 31 + (len(pages)-1) * 32
    ws_new.print_area = f"A1:Q{last_row}"

    # 페이지 구분선(인쇄 페이지 나누기): 각 페이지 끝(31행) 뒤에 강제 페이지브레이크
    from openpyxl.worksheet.pagebreak import Break
    for p_idx in range(len(pages)-1):
        break_row = 31 + p_idx*32  # 1페이지 끝 = 31, 2페이지 끝 = 63...
        ws_new.row_breaks.append(Break(id=break_row))

    # 변호사 계좌 정보
    ws_acct_src=wb_src_list["변호사 계좌 정보"]
    ws_acct_new=wb_new.create_sheet("변호사 계좌 정보")
    for col,dim in ws_acct_src.column_dimensions.items(): ws_acct_new.column_dimensions[col].width=dim.width
    for cell in ws_acct_src[1]:
        if cell.__class__.__name__=="MergedCell": continue
        nc=ws_acct_new.cell(1,cell.column,cell.value)
        if cell.has_style:
            nc.font=copy.copy(cell.font); nc.fill=copy.copy(cell.fill)
            nc.border=copy.copy(cell.border); nc.alignment=copy.copy(cell.alignment)
    src_l=lawyers_data or [
        {"name":r[0].value,"bank":r[1].value if len(r)>1 else "","bankCode":r[2].value if len(r)>2 else "",
         "acct":r[3].value if len(r)>3 else "","owner":r[4].value if len(r)>4 else "","email":r[5].value if len(r)>5 else ""}
        for r in ws_acct_src.iter_rows(min_row=2) if r[0].value
    ]
    for i,l in enumerate(src_l):
        r=2+i
        for col,key in [(1,"name"),(2,"bank"),(3,"bankCode"),(4,"acct"),(5,"owner"),(6,"email")]:
            ws_acct_new.cell(r,col).value=l.get(key,"") if isinstance(l,dict) else None

    # 지출목록
    list_src="26년 5월(국토부)" if biz_short=="국토부" else "26년 5월"
    ws_list_src=wb_src_list[list_src]
    ws_list_new=wb_new.create_sheet(f"26년 {mm}월({biz_label})")
    list_merges=[str(m) for m in ws_list_src.merged_cells.ranges]
    for col,dim in ws_list_src.column_dimensions.items(): ws_list_new.column_dimensions[col].width=dim.width
    for rn,dim in ws_list_src.row_dimensions.items(): ws_list_new.row_dimensions[rn].height=dim.height
    apply_merge_list(ws_list_new,list_merges,0)
    for row in ws_list_src.iter_rows(min_row=1,max_row=5):
        for cell in row:
            if cell.__class__.__name__=="MergedCell": continue
            nc=ws_list_new.cell(cell.row,cell.column)
            if nc.__class__.__name__=="MergedCell": continue
            if cell.has_style:
                nc.font=copy.copy(cell.font); nc.border=copy.copy(cell.border)
                nc.fill=copy.copy(cell.fill); nc.alignment=copy.copy(cell.alignment)

    total=sum((c.get("fee",0) or 0)+(c.get("stamp",0) or 0)+(c.get("delivery",0) or 0) for c in cases_data)
    prefix="(국토부) " if biz_short=="국토부" else ""
    set_val(ws_list_new,2,8,prefix+f"전세피해자 소송구조 {yy}년 {mm}월 사업비 지출 목록")
    set_val(ws_list_new,3,21,f"최종 수정: {yy}. {str(mm).zfill(2)}.")
    set_val(ws_list_new,4,21,total)
    for col,val in [(2,"결의서"),(3,"변호사"),(4,"접수번호"),(8,"신청인"),(9,"구조날짜"),
                    (10,"사건"),(11,"금액"),(14,"예금주"),(15,"은행"),(16,"은행번호"),
                    (17,"계좌"),(18,"비고"),(20,"메일")]:
        set_val(ws_list_new,5,col,val)
    for i,c in enumerate(cases_data):
        row=6+i
        amt=(c.get("fee",0) or 0)+(c.get("stamp",0) or 0)+(c.get("delivery",0) or 0)
        num=(c.get("num","") or "").replace("국부 ","").replace("서금 ","")
        if num.startswith("미인식"): num=""
        parts=num.split("-")
        yr=int(parts[0]) if len(parts)>0 and str(parts[0]).isdigit() else ""
        seq=int(parts[1]) if len(parts)>1 and str(parts[1]).isdigit() else ""
        linfo=lawyers_dict.get(c.get("lawyer",""),{})
        try: cdate=datetime.strptime(c.get("date",""),"%Y-%m-%d") if c.get("date") else datetime.today()
        except: cdate=datetime.today()
        for col,val in [
            (2,i+1),(3,c.get("lawyer","")),(4,yr),(5,seq),(6,num),(7,"재단"),
            (8,c.get("client","")),(9,cdate),(10,c.get("case","") or c.get("caseName","")),
            (11,amt),(12,num+c.get("client","")),(13,"재단"+c.get("client","")),
            (14,linfo.get("owner","")),(15,linfo.get("bank","")),(16,linfo.get("bankCode","")),
            (17,linfo.get("acct","")),(18,c.get("note","") or c.get("type","")),(20,linfo.get("email",""))
        ]: ws_list_new.cell(row,col).value=val
    ws_list_new.cell(6+len(cases_data),11).value=total

    # 저장 전 핵심 병합셀 강제 확인 및 재추가
    # 충돌하는 기존 병합 제거 후 정확한 범위로 재추가
    from openpyxl.utils import range_boundaries
    ws_resol = wb_new[new_name]
    required_merges_per_page = [
        "A3:E3", "E10:L10", "A31:K31"
    ]
    for p_idx in range(len(pages)):
        o = p_idx * 32
        for mc in required_merges_per_page:
            parts = mc.split(':')
            c1 = ''.join(c for c in parts[0] if c.isalpha())
            r1 = int(''.join(c for c in parts[0] if c.isdigit())) + o
            c2 = ''.join(c for c in parts[1] if c.isalpha())
            r2 = int(''.join(c for c in parts[1] if c.isdigit())) + o
            mc_shifted = f"{c1}{r1}:{c2}{r2}"
            # 목표 범위의 경계값
            min_col = column_index_from_string(c1)
            max_col = column_index_from_string(c2)
            # 같은 행+열 범위에 겹치는 기존 병합 제거
            to_remove = []
            for existing in list(ws_resol.merged_cells.ranges):
                if (existing.min_row <= r2 and existing.max_row >= r1 and
                    existing.min_col <= max_col and existing.max_col >= min_col):
                    to_remove.append(str(existing))
            for rm in to_remove:
                try: ws_resol.unmerge_cells(rm)
                except: pass
            # 정확한 범위로 재추가
            try: ws_resol.merge_cells(mc_shifted)
            except: pass

    # ── 정산보고서 시트 (외주사업-다. 소송대리 및 법률구조지원) ──
    build_settlement(wb_new, wb_src_list, cases_data, biz_short, yy, mm)

    buf=io.BytesIO(); wb_new.save(buf)
    return base64.b64encode(buf.getvalue()).decode()


def build_settlement(wb_new, wb_src_list, cases_data, biz_short, yy, mm):
    """정산보고서 시트 생성 - 원본 양식 복사 후 이번 달 데이터 채우기"""
    try:
        # 원본 정산 양식 로드
        wb_settle = load_workbook(io.BytesIO(base64.b64decode(SETTLE_B64)))
        src_sheet_name = '외주사업-다. 소송대리 및 법률구조지원'
        if src_sheet_name not in wb_settle.sheetnames:
            return
        ws_src = wb_settle[src_sheet_name]

        # 새 시트 생성
        ws_new = wb_new.create_sheet(f'정산보고서({mm}월)')

        # 병합셀 복사
        merge_strings = [str(m) for m in ws_src.merged_cells.ranges]
        for mc in merge_strings:
            try: ws_new.merge_cells(mc)
            except: pass

        # 열너비/행높이 복사
        for col, dim in ws_src.column_dimensions.items():
            ws_new.column_dimensions[col].width = dim.width
        for rn, dim in ws_src.row_dimensions.items():
            ws_new.row_dimensions[rn].height = dim.height

        # 셀 서식+값 복사 (수식은 값으로 대체)
        for row in ws_src.iter_rows():
            for cell in row:
                if cell.__class__.__name__ == 'MergedCell': continue
                nc = ws_new.cell(row=cell.row, column=cell.column)
                if nc.__class__.__name__ == 'MergedCell': continue
                # 수식은 복사 안 하고 None (나중에 실제값으로 채움)
                if cell.value and str(cell.value).startswith('='):
                    nc.value = None
                else:
                    nc.value = cell.value
                if cell.has_style:
                    nc.font = copy.copy(cell.font)
                    nc.border = copy.copy(cell.border)
                    nc.fill = copy.copy(cell.fill)
                    nc.number_format = cell.number_format
                    nc.alignment = copy.copy(cell.alignment)

        # ── 이번 달 데이터 계산 ──
        # 신청(A): type=="신청"인 착수금 합계
        amt_A = sum((c.get("fee",0) or 0) for c in cases_data
                    if c.get("type","") == "신청" and not c.get("_allowance"))
        # 본안(B): 민사/형사/행정 착수금 합계
        amt_B = sum((c.get("fee",0) or 0) for c in cases_data
                    if c.get("type","") in ("민사","형사","행정") and not c.get("_allowance"))
        # 직원수당(C): _allowance=True인 합계
        amt_C = sum((c.get("fee",0) or 0) for c in cases_data
                    if c.get("_allowance"))
        amt_D = amt_A + amt_B + amt_C  # 소계
        amt_E = round(amt_D * 0.048)   # 일반관리비 (4.8%)
        amt_G = round((amt_D + amt_E) * 0.1)  # 부가가치세 10%
        amt_H = amt_D + amt_E + amt_G  # 월계

        # 행 번호 찾기: A열 값이 datetime이고 month==mm인 행
        target_row = None
        for row in ws_new.iter_rows(min_row=22, max_row=33):
            cell = row[0]  # A열
            if hasattr(cell.value, 'month') and cell.value.month == mm:
                target_row = cell.row
                break

        if target_row:
            # B(신청A), C(본안B), D(직원수당C) 채우기
            ws_new.cell(target_row, 2).value = amt_A if amt_A else None
            ws_new.cell(target_row, 3).value = amt_B if amt_B else None
            ws_new.cell(target_row, 4).value = amt_C if amt_C else None
            # E(소계), F(일반관리비), G(부가가치세), H(월계) - 계산값으로
            ws_new.cell(target_row, 5).value = amt_D if amt_D else None
            ws_new.cell(target_row, 6).value = amt_E if amt_E else None
            ws_new.cell(target_row, 7).value = amt_G if amt_G else None
            ws_new.cell(target_row, 8).value = amt_H if amt_H else None

        # 총계 행(34) 계산
        row34_B = sum(ws_new.cell(r, 2).value or 0 for r in range(22, 34))
        row34_C = sum(ws_new.cell(r, 3).value or 0 for r in range(22, 34))
        row34_D = sum(ws_new.cell(r, 4).value or 0 for r in range(22, 34))
        row34_E = sum(ws_new.cell(r, 5).value or 0 for r in range(22, 34))
        row34_F = sum(ws_new.cell(r, 6).value or 0 for r in range(22, 34))
        row34_G = sum(ws_new.cell(r, 7).value or 0 for r in range(22, 34))
        row34_H = sum(ws_new.cell(r, 8).value or 0 for r in range(22, 34))
        ws_new.cell(34, 2).value = row34_B
        ws_new.cell(34, 3).value = row34_C
        ws_new.cell(34, 4).value = row34_D
        ws_new.cell(34, 5).value = row34_E
        ws_new.cell(34, 6).value = row34_F
        ws_new.cell(34, 7).value = row34_G
        ws_new.cell(34, 8).value = row34_H

        # 잔여예산 행(35): 예산 - 총계
        budget_B = ws_src.cell(6, 3).value or 0   # 신청A 예산
        budget_C = ws_src.cell(7, 3).value or 0   # 본안B 예산
        budget_D = ws_src.cell(8, 3).value or 0   # 직원수당C 예산
        budget_E = ws_src.cell(10, 3).value or 0  # 일반관리비 예산
        budget_G = ws_src.cell(11, 3).value or 0  # 부가가치세 예산
        ws_new.cell(35, 2).value = budget_B - row34_B
        ws_new.cell(35, 3).value = budget_C - row34_C
        ws_new.cell(35, 4).value = budget_D - row34_D
        ws_new.cell(35, 5).value = (budget_B+budget_C+budget_D) - row34_E
        ws_new.cell(35, 6).value = budget_E - row34_F
        ws_new.cell(35, 7).value = budget_G - row34_G
        ws_new.cell(35, 8).value = (budget_B+budget_C+budget_D+budget_E+budget_G) - row34_H

    except Exception as e:
        import traceback
        print(f"정산보고서 생성 오류: {e}\n{traceback.format_exc()}")


class handler(BaseHTTPRequestHandler):
    def do_OPTIONS(self): self.send_response(200); self._cors(); self.end_headers()
    def do_POST(self):
        try:
            length=int(self.headers.get("Content-Length",0))
            body=self.rfile.read(length); data=json.loads(body)
            cases=data.get("cases",[]); lawyers=data.get("lawyers",[])
            biz_short=data.get("bizShort","국토부"); today=datetime.today()
            yy=int(data.get("yy",today.year)); mm=int(data.get("mm",today.month)); dd=int(data.get("dd",today.day))
            b64=build_excel(cases,lawyers,biz_short,yy,mm,dd)
            result=json.dumps({"xlsx":b64}).encode("utf-8")
            self.send_response(200); self._cors()
            self.send_header("Content-Type","application/json")
            self.send_header("Content-Length",str(len(result))); self.end_headers()
            self.wfile.write(result)
        except Exception as e:
            import traceback
            err=json.dumps({"error":str(e),"trace":traceback.format_exc()}).encode("utf-8")
            self.send_response(500); self._cors()
            self.send_header("Content-Type","application/json")
            self.send_header("Content-Length",str(len(err))); self.end_headers()
            self.wfile.write(err)
    def _cors(self):
        self.send_header("Access-Control-Allow-Origin","*")
        self.send_header("Access-Control-Allow-Methods","POST, OPTIONS")
        self.send_header("Access-Control-Allow-Headers","Content-Type")
